#include <stdio.h>
#include <limits.h>

int maxORegionValue(int m, int n, int matrix[m][n]) {
    int maxValue = INT_MIN;
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int k = i + 1; k <= m; k++) {
                for (int l = j + 1; l <= n; l++) {
                    for (int x = i + 1; x < k - 1; x++) {
                        for (int y = j + 1; y < l - 1; y++) {
                            int outerSum = 0, innerSum = 0;
                            for (int a = i; a < k; a++) {
                                for (int b = j; b < l; b++) {
                                    outerSum += matrix[a][b];
                                }
                            }
                            for (int a = x; a < k - 1; a++) {
                                for (int b = y; b < l - 1; b++) {
                                    innerSum += matrix[a][b];
                                }
                            }
                            maxValue = (outerSum - innerSum > maxValue) ? outerSum - innerSum : maxValue;
                        }
                    }
                }
            }
        }
    }
    return maxValue;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int m, n;
        scanf("%d %d", &m, &n);
        int matrix[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &matrix[i][j]);
            }
        }
        printf("%d\n", maxORegionValue(m, n, matrix));
    }
    return 0;
}

